howItWorks.step1Code:
yourCenturion.understand({
  mission: 'yours',
  privacy: 'absolute',
  home: 'defined',
  leavesHome: false
})

// Zrozumiano – i tak zostanie.

howItWorks.step2Code:
yourCenturion.place({
  where: 'your home',
  outsideWorld: 'your choice',
  leaves: false
})

// Zadomowiony. Nic nie wycieka.

howItWorks.step3Code:
yourCenturion.live({
  always: true,
  learns: 'from you only',
  shares: 'nothing',
  companySees: 'nothing'
})

// Prywatny. Wierny. Twój.

developers.code1:
// Umiejętności od innych osób nie są zaufane
skill.fromSomeoneElse({
  trust: 'none',
  risk: 'stolen secrets | hidden behaviour'
})

// Centurion nie zainstaluje
// umiejętności obcego wyłącznie na Twoje słowo.

developers.code2:
centurion.makeSkill({
  for: 'what you actually need',
  basedOn: 'your life's mission',
  author: 'your Centurion'
})

// Tworzy umiejętności. Nie
// kupuje ich w sklepie.

developers.code3:
work.continues({
  gap: 'found',
  skill: 'made now',
  stays: 'with you'
})

// Umiejętności pojawiają się, gdy są potrzebne —
// i zostają w Twoim domu, pod Twoją kontrolą.

developers.code4:
loop.run({
  notice: true,
  act: true,
  learn: true,
  improve: true
})

// Zauważ. Działaj. Ucz się. Ulepszaj.
// Umiejętności stają się lepsze z użyciem —
// bez raportowania na zewnątrz.

